fn writeReplyMessage(ctx: *Context, msg_type: protocol.MessageType, message: []const u8) CmdError!void {
    if (ctx.reply_fd) |fd| {
        protocol.sendMessage(fd, msg_type, message) catch return CmdError.CommandFailed;
        return;
    }

    const target_fd: std.c.fd_t = switch (msg_type) {
        .error_msg => 2,
        else => 1,
    };
    _ = std.c.write(target_fd, message.ptr, message.len);
}

fn writeOutput(ctx: *Context, comptime fmt: []const u8, args: anytype) CmdError!void {
    var buf: [1024]u8 = undefined;
    const message = std.fmt.bufPrint(&buf, fmt, args) catch return CmdError.CommandFailed;
    try writeReplyMessage(ctx, .output, message);
}

/// Send clipboard data to all clients attached to the session via OSC 52.
fn sendOsc52Clipboard(ctx: *Context, data: []const u8) void {
    const session = ctx.session orelse return;
    const osc52 = clipboard_mod.Clipboard.encodeOsc52Set(ctx.allocator, data) catch return;
    defer ctx.allocator.free(osc52);
    for (ctx.server.clients.items) |client| {
        if (client.session == session and client.fd >= 0) {
            protocol.sendMessage(client.fd, .output, osc52) catch {};
        }
    }
}

fn spawnWindowPane(alloc: std.mem.Allocator, shell: [:0]const u8, sx: u32, sy: u32) CmdError!*Pane {
    const pane = Pane.init(alloc, sx, sy) catch return CmdError.OutOfMemory;
    errdefer pane.deinit();

    var pty = Pty.openPty() catch return CmdError.CommandFailed;
    pty.forkExec(shell, null) catch return CmdError.CommandFailed;
    pty.resize(@intCast(sx), @intCast(sy));
    pane.fd = pty.master_fd;
    pane.pid = pty.pid;
    return pane;
}

fn parseTargetWindow(args: []const []const u8) ?u32 {
    var i: usize = 0;
    while (i < args.len) : (i += 1) {
        if (!std.mem.eql(u8, args[i], "-t") or i + 1 >= args.len) continue;
        i += 1;
        return parseWindowTargetNumber(args[i]);
    }
    return null;
}

fn parseWindowTargetNumber(target: []const u8) ?u32 {
    if (target.len >= 2 and target[0] == ':') {
        return std.fmt.parseInt(u32, target[1..], 10) catch null;
    }
    return std.fmt.parseInt(u32, target, 10) catch null;
}

/// Resolved target from tmux target syntax.
const ResolvedTarget = struct {
    session: ?*Session = null,
    window: ?*Window = null,
    pane: ?*Pane = null,
};

/// Resolve a tmux-style target string: [session:][window][.pane]
/// Supports:
///   - Session by name or `$` (last)
///   - Window by index, name, `!` (last), `+` (next), `-` (prev)
///   - Pane by index, `%id`, `!` (last), `+` (next), `-` (prev)
fn resolveTarget(server: *Server, current: *const Context, target: []const u8) ResolvedTarget {
    var result = ResolvedTarget{
        .session = current.session,
        .window = current.window,
        .pane = current.pane,
    };
    if (target.len == 0) return result;

    var session_part: ?[]const u8 = null;
    var window_part: ?[]const u8 = null;
    var pane_part: ?[]const u8 = null;

    // Split on ':' for session:window.pane
    var rest = target;
    if (std.mem.indexOfScalar(u8, rest, ':')) |colon| {
        session_part = rest[0..colon];
        rest = rest[colon + 1 ..];
    }
    // Split on '.' for window.pane
    if (std.mem.indexOfScalar(u8, rest, '.')) |dot| {
        window_part = rest[0..dot];
        pane_part = rest[dot + 1 ..];
    } else if (rest.len > 0) {
        window_part = rest;
    }

    // Resolve session
    if (session_part) |sp| {
        if (sp.len > 0) {
            result.session = resolveSessionToken(server, current.session, sp);
        }
    }

    const session = result.session orelse return result;

    // Resolve window
    if (window_part) |wp| {
        if (wp.len > 0) {
            result.window = resolveWindowToken(session, wp);
        }
    }

    const window = result.window orelse return result;

    // Resolve pane
    if (pane_part) |pp| {
        if (pp.len > 0) {
            result.pane = resolvePaneToken(window, pp);
        }
    }

    return result;
}

fn resolveSessionToken(server: *Server, current: ?*Session, token: []const u8) ?*Session {
    if (std.mem.eql(u8, token, "$")) {
        // Last session
        return if (server.sessions.items.len > 0) server.sessions.items[server.sessions.items.len - 1] else null;
    }
    // Try by name
    if (server.findSession(token)) |s| return s;
    // Try by id ($N)
    if (token.len > 1 and token[0] == '$') {
        const id = std.fmt.parseInt(u32, token[1..], 10) catch return current;
        for (server.sessions.items) |s| {
            if (s.id == id) return s;
        }
    }
    return current;
}

fn resolveWindowToken(session: *Session, token: []const u8) ?*Window {
    if (std.mem.eql(u8, token, "!")) {
        return session.last_window;
    }
    if (std.mem.eql(u8, token, "+")) {
        if (session.active_window) |aw| {
            for (session.windows.items, 0..) |w, i| {
                if (w == aw) return session.windows.items[(i + 1) % session.windows.items.len];
            }
        }
        return session.active_window;
    }
    if (std.mem.eql(u8, token, "-")) {
        if (session.active_window) |aw| {
            for (session.windows.items, 0..) |w, i| {
                if (w == aw) return session.windows.items[if (i == 0) session.windows.items.len - 1 else i - 1];
            }
        }
        return session.active_window;
    }
    // Try by index (base-index adjusted)
    if (std.fmt.parseInt(u32, token, 10) catch null) |num| {
        return session.findWindowByNumber(num);
    }
    // Try by name
    for (session.windows.items) |w| {
        if (std.mem.eql(u8, w.name, token)) return w;
    }
    return session.active_window;
}

fn resolvePaneToken(window: *Window, token: []const u8) ?*Pane {
    if (std.mem.eql(u8, token, "!")) {
        return window.last_pane;
    }
    if (std.mem.eql(u8, token, "+") or std.mem.eql(u8, token, ".+")) {
        if (window.active_pane) |ap| {
            for (window.panes.items, 0..) |p, i| {
                if (p == ap) return window.panes.items[(i + 1) % window.panes.items.len];
            }
        }
        return window.active_pane;
    }
    if (std.mem.eql(u8, token, "-") or std.mem.eql(u8, token, ".-")) {
        if (window.active_pane) |ap| {
            for (window.panes.items, 0..) |p, i| {
                if (p == ap) return window.panes.items[if (i == 0) window.panes.items.len - 1 else i - 1];
            }
        }
        return window.active_pane;
    }
    // %N pane id
    if (token.len >= 2 and token[0] == '%') {
        const id = std.fmt.parseInt(u32, token[1..], 10) catch return window.active_pane;
        for (window.panes.items) |p| {
            if (p.id == id) return p;
        }
        return null;
    }
    // Numeric index
    if (std.fmt.parseInt(usize, token, 10) catch null) |idx| {
        if (idx < window.panes.items.len) return window.panes.items[idx];
    }
    return window.active_pane;
}

/// Parse -t from args and resolve to session/window/pane, updating ctx.
fn resolveTargetFromArgs(ctx: *Context, args: []const []const u8) void {
    const target_str = parseNamedOption(args, "-t") orelse return;
    const resolved = resolveTarget(ctx.server, ctx, target_str);
    if (resolved.session) |s| ctx.session = s;
    if (resolved.window) |w| ctx.window = w;
    if (resolved.pane) |p| ctx.pane = p;
}

fn defaultShell(session: ?*Session) [:0]const u8 {
    if (session) |s| return s.options.default_shell;
    return "/bin/sh";
}

fn defaultShellFromContext(ctx: *const Context) [:0]const u8 {
    if (ctx.session) |s| return s.options.default_shell;
    if (ctx.server.global_default_shell) |shell| return shell;
    return "/bin/sh";
}

/// Get terminal dimensions from context: active window > client > 80x24.
fn terminalSize(ctx: *const Context) struct { cols: u32, rows: u32 } {
    if (ctx.session) |s| {
        if (s.active_window) |w| return .{ .cols = w.sx, .rows = w.sy };
    }
    if (ctx.client_index) |ci| {
        if (ci < ctx.server.clients.items.len) {
            const client = &ctx.server.clients.items[ci];
            return .{ .cols = client.cols, .rows = client.rows };
        }
    }
    return .{ .cols = 80, .rows = 24 };
}

/// Build a FormatContext from the current command context.
fn makeFormatContext(ctx: *const Context) format_mod.FormatContext {
    var fc = format_mod.FormatContext{};
    if (ctx.session) |s| {
        fc.session_name = s.name;
        fc.session_id = s.id;
        const window = ctx.window orelse s.active_window;
        if (window) |w| {
            fc.window_name = w.name;
            for (s.windows.items, 0..) |win, idx| {
                if (win == w) {
                    fc.window_index = s.options.base_index + @as(u32, @intCast(idx));
                    fc.window_active = s.active_window == w;
                    break;
                }
            }
            const pane = ctx.pane orelse w.active_pane;
            if (pane) |p| {
                for (w.panes.items, 0..) |window_pane, idx| {
                    if (window_pane == p) {
                        fc.pane_index = @intCast(idx);
                        break;
                    }
                }
                fc.pane_pid = p.pid;
            }
        }
    }
    return fc;
}

fn resolvedTargetContext(ctx: *const Context, args: []const []const u8) Context {
    var target_ctx = ctx.*;
    resolveTargetFromArgs(&target_ctx, args);
    return target_ctx;
}

const ClockTm = extern struct {
    tm_sec: i32,
    tm_min: i32,
    tm_hour: i32,
    tm_mday: i32,
    tm_mon: i32,
    tm_year: i32,
    tm_wday: i32,
    tm_yday: i32,
    tm_isdst: i32,
};

extern "c" fn time(timer: ?*i64) i64;
extern "c" fn localtime(timer: *const i64) ?*ClockTm;
extern "c" fn strftime(buf: [*]u8, maxsize: usize, format: [*:0]const u8, tm: *const ClockTm) usize;

fn parseNamedOption(args: []const []const u8, flag: []const u8) ?[]const u8 {
    var i: usize = 0;
    while (i < args.len) : (i += 1) {
        if (std.mem.eql(u8, args[i], flag) and i + 1 < args.len) {
            return args[i + 1];
        }
    }
    return null;
}

fn parseBooleanValue(value: []const u8) ?bool {
    if (std.ascii.eqlIgnoreCase(value, "on") or
        std.ascii.eqlIgnoreCase(value, "yes") or
        std.mem.eql(u8, value, "1"))
    {
        return true;
    }
    if (std.ascii.eqlIgnoreCase(value, "off") or
        std.ascii.eqlIgnoreCase(value, "no") or
        std.mem.eql(u8, value, "0"))
    {
        return false;
    }
    return null;
}

fn parsePrefixValue(value: []const u8) ?u21 {
    const parsed = key_string.stringToKey(value) orelse return null;
    if (parsed.mods.meta or parsed.mods.shift) return null;
    if (!parsed.mods.ctrl) return parsed.key;

    if (parsed.key == ' ') return 0;
    if (parsed.key >= 'a' and parsed.key <= 'z') return parsed.key - 'a' + 1;
    if (parsed.key >= 'A' and parsed.key <= 'Z') return parsed.key - 'A' + 1;
    return null;
}

fn isWindowOptionName(name: []const u8) bool {
    return std.mem.eql(u8, name, "mode-keys") or
        std.mem.eql(u8, name, "window-status-format") or
        std.mem.eql(u8, name, "aggressive-resize") or
        std.mem.eql(u8, name, "remain-on-exit");
}

fn applyWindowOption(window: *Window, name: []const u8, value: []const u8) !void {
    if (std.mem.eql(u8, name, "mode-keys")) {
        try window.setModeKeys(value);
        return;
    }
    if (std.mem.eql(u8, name, "window-status-format")) {
        try window.setWindowStatusFormat(value);
        return;
    }
    if (std.mem.eql(u8, name, "aggressive-resize")) {
        window.options.aggressive_resize = parseBooleanValue(value) orelse return error.InvalidArgs;
        return;
    }
    if (std.mem.eql(u8, name, "remain-on-exit")) {
        window.options.remain_on_exit = parseBooleanValue(value) orelse return error.InvalidArgs;
        return;
    }
    return error.CommandFailed;
}

fn restoreDefaultWindowOption(window: *Window, name: []const u8) void {
    if (std.mem.eql(u8, name, "mode-keys")) {
        window.setModeKeys("emacs") catch {};
    } else if (std.mem.eql(u8, name, "window-status-format")) {
        window.setWindowStatusFormat("#I:#W#F") catch {};
    } else if (std.mem.eql(u8, name, "aggressive-resize")) {
        window.options.aggressive_resize = false;
    } else if (std.mem.eql(u8, name, "remain-on-exit")) {
        window.options.remain_on_exit = false;
    }
}

fn applyGlobalWindowOption(server: *Server, name: []const u8, value: []const u8) !void {
    if (std.mem.eql(u8, name, "mode-keys")) {
        const owned = try server.allocator.dupe(u8, value);
        server.allocator.free(server.window_defaults.mode_keys);
        server.window_defaults.mode_keys = owned;
    } else if (std.mem.eql(u8, name, "window-status-format")) {
        const owned = try server.allocator.dupe(u8, value);
        server.allocator.free(server.window_defaults.window_status_format);
        server.window_defaults.window_status_format = owned;
    } else if (std.mem.eql(u8, name, "aggressive-resize")) {
        server.window_defaults.aggressive_resize = parseBooleanValue(value) orelse return error.InvalidArgs;
    } else if (std.mem.eql(u8, name, "remain-on-exit")) {
        server.window_defaults.remain_on_exit = parseBooleanValue(value) orelse return error.InvalidArgs;
    } else {
        return error.CommandFailed;
    }

    for (server.sessions.items) |session| {
        for (session.windows.items) |window| {
            applyWindowOption(window, name, value) catch {};
        }
    }
}

fn restoreGlobalWindowOption(server: *Server, name: []const u8) void {
    if (std.mem.eql(u8, name, "mode-keys")) {
        const owned = server.allocator.dupe(u8, "emacs") catch return;
        server.allocator.free(server.window_defaults.mode_keys);
        server.window_defaults.mode_keys = owned;
    } else if (std.mem.eql(u8, name, "window-status-format")) {
        const owned = server.allocator.dupe(u8, "#I:#W#F") catch return;
        server.allocator.free(server.window_defaults.window_status_format);
        server.window_defaults.window_status_format = owned;
    } else if (std.mem.eql(u8, name, "aggressive-resize")) {
        server.window_defaults.aggressive_resize = false;
    } else if (std.mem.eql(u8, name, "remain-on-exit")) {
        server.window_defaults.remain_on_exit = false;
    } else {
        return;
    }

    for (server.sessions.items) |session| {
        for (session.windows.items) |window| {
            restoreDefaultWindowOption(window, name);
        }
    }
}

fn showWindowOptionValue(ctx: *Context, name: []const u8, is_global: bool, is_value_only: bool) CmdError!bool {
    if (std.mem.eql(u8, name, "mode-keys")) {
        const value = if (is_global)
            ctx.server.window_defaults.mode_keys
        else
            (ctx.window orelse return CmdError.WindowNotFound).options.mode_keys;
        if (is_value_only) {
            try writeOutput(ctx, "{s}\n", .{value});
        } else {
            try writeOutput(ctx, "mode-keys {s}\n", .{value});
        }
        return true;
    }
    if (std.mem.eql(u8, name, "window-status-format")) {
        const value = if (is_global)
            ctx.server.window_defaults.window_status_format
        else
            (ctx.window orelse return CmdError.WindowNotFound).options.window_status_format;
        if (is_value_only) {
            try writeOutput(ctx, "{s}\n", .{value});
        } else {
            try writeOutput(ctx, "window-status-format {s}\n", .{value});
        }
        return true;
    }
    if (std.mem.eql(u8, name, "aggressive-resize")) {
        const enabled = if (is_global)
            ctx.server.window_defaults.aggressive_resize
        else
            (ctx.window orelse return CmdError.WindowNotFound).options.aggressive_resize;
        const value = if (enabled) "on" else "off";
        if (is_value_only) {
            try writeOutput(ctx, "{s}\n", .{value});
        } else {
            try writeOutput(ctx, "aggressive-resize {s}\n", .{value});
        }
        return true;
    }
    if (std.mem.eql(u8, name, "remain-on-exit")) {
        const enabled = if (is_global)
            ctx.server.window_defaults.remain_on_exit
        else
            (ctx.window orelse return CmdError.WindowNotFound).options.remain_on_exit;
        const value = if (enabled) "on" else "off";
        if (is_value_only) {
            try writeOutput(ctx, "{s}\n", .{value});
        } else {
            try writeOutput(ctx, "remain-on-exit {s}\n", .{value});
        }
        return true;
    }
    return false;
}

fn resolvePasteBuffer(ctx: *Context, name: ?[]const u8) CmdError!*paste_mod.PasteBuffer {
    if (name) |buffer_name| {
        return ctx.server.paste_stack.getByName(buffer_name) orelse CmdError.BufferNotFound;
    }
    return ctx.server.paste_stack.get(0) orelse CmdError.BufferNotFound;
}

fn extractGridLineSlice(alloc: std.mem.Allocator, pane_state: anytype, absolute_y: u32, start_x: u32, end_x: u32) ![]u8 {
    const grid = &pane_state.screen.grid;
    const total_lines = grid.hsize + grid.rows;
    if (absolute_y >= total_lines) return try alloc.dupe(u8, "");

    const line = if (absolute_y < grid.hsize)
        grid.getHistoryLine(absolute_y)
    else
        grid.getLine(absolute_y - grid.hsize);

    const max_x = @min(end_x, grid.cols -| 1);
    if (start_x > max_x) return try alloc.dupe(u8, "");

    var buf: std.ArrayListAligned(u8, null) = .empty;
    defer buf.deinit(alloc);
    var x = start_x;
    while (x <= max_x) : (x += 1) {
        const cell = line.getCell(x);
        const ch: u8 = if (cell.codepoint == 0)
            ' '
        else if (cell.codepoint < 0x80)
            @truncate(cell.codepoint)
        else
            '?';
        try buf.append(alloc, ch);
    }

    while (buf.items.len > 0 and buf.items[buf.items.len - 1] == ' ') {
        _ = buf.pop();
    }
    return try buf.toOwnedSlice(alloc);
}

fn extractCopySelection(alloc: std.mem.Allocator, pane_state: anytype, state: *const copy_mod.CopyState) ![]u8 {
    const grid = &pane_state.screen.grid;
    const total_lines = grid.hsize + grid.rows;
    if (total_lines == 0) return try alloc.dupe(u8, "");

    const start_y = @min(state.sel_start_y, state.cy);
    const end_y = @min(@max(state.sel_start_y, state.cy), total_lines - 1);
    const start_x = @min(state.sel_start_x, state.cx);
    const end_x = @max(state.sel_start_x, state.cx);

    var out: std.ArrayListAligned(u8, null) = .empty;
    errdefer out.deinit(alloc);

    var y = start_y;
    while (y <= end_y) : (y += 1) {
        const line_text = if (state.mode == .visual_line)
            try extractGridLineSlice(alloc, pane_state, y, 0, grid.cols -| 1)
        else if (start_y == end_y)
            try extractGridLineSlice(alloc, pane_state, y, start_x, end_x)
        else if (y == start_y)
            try extractGridLineSlice(alloc, pane_state, y, start_x, grid.cols -| 1)
        else if (y == end_y)
            try extractGridLineSlice(alloc, pane_state, y, 0, end_x)
        else
            try extractGridLineSlice(alloc, pane_state, y, 0, grid.cols -| 1);
        defer alloc.free(line_text);

        try out.appendSlice(alloc, line_text);
        if (y != end_y) try out.append(alloc, '\n');
    }

    return try out.toOwnedSlice(alloc);
}

/// Search the scrollback buffer for a pattern, moving the cursor to the match.
/// `forward` = true searches downward from current position, false searches upward.
fn searchScrollback(alloc: std.mem.Allocator, pane_state: anytype, state: *copy_mod.CopyState, forward: bool) void {
    if (state.search_len == 0) return;
    const pattern = state.search_buf[0..state.search_len];
    const grid = &pane_state.screen.grid;
    const total_lines = grid.hsize + grid.rows;
    if (total_lines == 0) return;

    // Search line by line from the current position.
    const start_y = state.cy;
    var checked: u32 = 0;
    while (checked < total_lines) : (checked += 1) {
        const y = if (forward)
            (start_y + 1 + checked) % total_lines
        else
            (start_y + total_lines - 1 - checked) % total_lines;

        const line_text = extractGridLineSlice(alloc, pane_state, y, 0, grid.cols -| 1) catch continue;
        defer alloc.free(line_text);

        // Find pattern in the line.
        if (std.mem.indexOf(u8, line_text, pattern)) |col| {
            state.cy = y;
            state.cx = @intCast(col);
            return;
        }
    }
}

fn handleCopyModeAction(ctx: *Context, pane: *Pane, pane_state: anytype, action: copy_mod.CopyAction) CmdError!void {
    switch (action) {
        .move_cursor, .start_selection => {},
        .search_next => if (pane.copy_state) |*state| {
            searchScrollback(ctx.allocator, pane_state, state, true);
        },
        .search_prev => if (pane.copy_state) |*state| {
            searchScrollback(ctx.allocator, pane_state, state, false);
        },
        .scroll_up => if (pane.copy_state) |*state| {
            if (state.cy > 0) state.cy -= 1;
        },
        .scroll_down => if (pane.copy_state) |*state| {
            const max_y = pane_state.screen.grid.hsize + pane_state.screen.grid.rows -| 1;
            state.cy = @min(max_y, state.cy + 1);
        },
        .page_up => if (pane.copy_state) |*state| {
            const step = pane_state.screen.grid.rows;
            state.cy = state.cy -| step;
        },
        .page_down => if (pane.copy_state) |*state| {
            const step = pane_state.screen.grid.rows;
            const max_y = pane_state.screen.grid.hsize + pane_state.screen.grid.rows -| 1;
            state.cy = @min(max_y, state.cy + step);
        },
        .cancel => pane.copy_state = null,
        .copy_selection => {
            const state = pane.copy_state orelse return;
            const text = extractCopySelection(ctx.allocator, pane_state, &state) catch return CmdError.CommandFailed;
            defer ctx.allocator.free(text);
            ctx.server.paste_stack.push(text, null) catch return CmdError.OutOfMemory;
            // Send to system clipboard via OSC 52.
            sendOsc52Clipboard(ctx, text);
            pane.copy_state = null;
        },
    }
}

fn handleCopyModeKey(ctx: *Context, pane: *Pane, key_arg: []const u8) CmdError!bool {
    const pane_state = ctx.server.session_loop.getPane(pane.id) orelse return false;
    var handled = false;

    if (key_string.stringToKey(key_arg)) |result| {
        if (pane.copy_state) |*state| {
            const mods: copy_mod.Modifiers = .{
                .ctrl = result.mods.ctrl,
                .meta = result.mods.meta,
                .shift = result.mods.shift,
            };
            if (state.handleKey(result.key, mods)) |action| {
                try handleCopyModeAction(ctx, pane, pane_state, action);
            }
            handled = true;
        }
    } else if (pane.copy_state) |*state| {
        for (key_arg) |byte| {
            if (state.handleKey(byte, .{})) |action| {
                try handleCopyModeAction(ctx, pane, pane_state, action);
            }
        }
        handled = true;
    }

    return handled;
}

fn appendPromptBytes(state: *PromptState, bytes: []const u8) void {
    const remaining = state.buffer.len - state.len;
    const copy_len = @min(remaining, bytes.len);
    if (copy_len == 0) return;
    @memcpy(state.buffer[state.len .. state.len + copy_len], bytes[0..copy_len]);
    state.len += copy_len;
}

fn executeCommandString(ctx: *Context, command_text: []const u8) CmdError!void {
    const registry = ctx.registry orelse return CmdError.CommandFailed;
    if (command_text.len == 0) return;

    var parser = config_parser.ConfigParser.init(ctx.allocator, command_text);
    var commands = parser.parseAll() catch return CmdError.CommandFailed;
    defer {
        for (commands.items) |*command| command.deinit(ctx.allocator);
        commands.deinit(ctx.allocator);
    }
    if (commands.items.len == 0) return CmdError.InvalidArgs;

    for (commands.items) |*command| {
        try registry.executeParsed(ctx, command);
    }
}

fn executePromptBuffer(ctx: *Context, pane: *Pane) CmdError!void {
    const prompt_state = pane.prompt_state orelse return;
    const command_text = prompt_state.buffer[0..prompt_state.len];

    pane.prompt_state = null;
    try executeCommandString(ctx, command_text);
}

fn handlePromptKey(ctx: *Context, pane: *Pane, key_arg: []const u8) CmdError!bool {
    var prompt_state = &(pane.prompt_state orelse return false);

    if (std.mem.eql(u8, key_arg, "Enter")) {
        try executePromptBuffer(ctx, pane);
        return true;
    }
    if (std.mem.eql(u8, key_arg, "Escape")) {
        pane.prompt_state = null;
        return true;
    }
    if (std.mem.eql(u8, key_arg, "BSpace")) {
        if (prompt_state.len > 0) prompt_state.len -= 1;
        return true;
    }
    if (std.mem.eql(u8, key_arg, "Space")) {
        appendPromptBytes(prompt_state, " ");
        return true;
    }
    if (std.mem.eql(u8, key_arg, "Tab")) {
        appendPromptBytes(prompt_state, "\t");
        return true;
    }

    appendPromptBytes(prompt_state, key_arg);
    return true;
}

fn addChooseTreeEntry(state: *ChooseTreeState, label: []const u8, depth: u8, has_children: bool, session: *Session, window: ?*Window, pane: ?*Pane) CmdError!void {
    const owned_label = state.allocator.dupe(u8, label) catch return CmdError.OutOfMemory;
    errdefer state.allocator.free(owned_label);
    state.labels.append(state.allocator, owned_label) catch return CmdError.OutOfMemory;
    state.tree.addItem(.{
        .label = owned_label,
        .depth = depth,
        .expanded = true,
        .has_children = has_children,
        .tag = @intCast(state.items.items.len),
    }) catch return CmdError.OutOfMemory;
    state.items.append(state.allocator, .{
        .session = @ptrCast(session),
        .window = if (window) |w| @ptrCast(w) else null,
        .pane = if (pane) |p| @ptrCast(p) else null,
    }) catch return CmdError.OutOfMemory;
}

fn currentChooseTreeState(ctx: *Context, pane: ?*Pane) ?*ChooseTreeState {
    if (ctx.server.choose_tree_state) |*state| return state;
    if (ctx.client_index) |client_index| {
        if (client_index < ctx.server.clients.items.len) {
            if (ctx.server.clients.items[client_index].choose_tree_state) |*state| return state;
        }
    }
    if (pane) |p| {
        if (p.choose_tree_state) |*state| return state;
    }
    return null;
}

fn clearChooseTreeState(ctx: *Context, pane: ?*Pane) void {
    if (ctx.server.choose_tree_state) |*state| {
        state.deinit();
        ctx.server.choose_tree_state = null;
    }
    if (ctx.client_index) |client_index| {
        if (client_index < ctx.server.clients.items.len) {
            if (ctx.server.clients.items[client_index].choose_tree_state) |*state| {
                state.deinit();
            }
            ctx.server.clients.items[client_index].choose_tree_state = null;
        }
    }
    if (pane) |p| {
        if (p.choose_tree_state) |*state| {
            state.deinit();
        }
        p.choose_tree_state = null;
    }
}

fn renderChooseTree(ctx: *Context, pane: ?*Pane) CmdError!void {
    const state = currentChooseTreeState(ctx, pane) orelse return CmdError.CommandFailed;
    const rendered = state.tree.render(ctx.allocator) catch return CmdError.OutOfMemory;
    defer ctx.allocator.free(rendered);
    try writeOutput(ctx, "{s}", .{rendered});
}

fn handleChooseTreeSelect(ctx: *Context, pane: ?*Pane, item_index: usize) CmdError!void {
    const state = currentChooseTreeState(ctx, pane) orelse return CmdError.CommandFailed;
    if (item_index >= state.items.items.len) return CmdError.InvalidArgs;
    const item = state.items.items[item_index];

    // Buffer chooser selection: paste selected buffer into active pane.
    if (item.buffer_index) |buf_idx| {
        const buf = ctx.server.paste_stack.get(buf_idx) orelse return CmdError.BufferNotFound;
        if (ctx.session) |sel_session| {
            if (sel_session.active_window) |sel_window| {
                if (sel_window.active_pane) |sel_pane| {
                    if (sel_pane.fd >= 0) {
                        _ = std.c.write(sel_pane.fd, buf.data.ptr, buf.data.len);
                    }
                }
            }
        }
        clearChooseTreeState(ctx, pane);
        return;
    }

    const session: *Session = @ptrCast(@alignCast(item.session orelse return CmdError.SessionNotFound));
    ctx.session = session;
    ctx.server.default_session = session;
    if (item.window) |window_ptr| {
        const window: *Window = @ptrCast(@alignCast(window_ptr));
        session.selectWindow(window);
        ctx.window = window;
        if (item.pane) |pane_ptr| {
            const selected_pane: *Pane = @ptrCast(@alignCast(pane_ptr));
            window.selectPane(selected_pane);
            ctx.pane = selected_pane;
        } else {
            ctx.pane = window.active_pane;
        }
    } else {
        ctx.window = session.active_window;
        ctx.pane = if (ctx.window) |window| window.active_pane else null;
    }
    clearChooseTreeState(ctx, pane);
}

fn handleChooseTreeKey(ctx: *Context, pane: ?*Pane, key_arg: []const u8) CmdError!bool {
    if (currentChooseTreeState(ctx, pane) == null) return false;

    const key: u21 = if (key_string.stringToKey(key_arg)) |result|
        result.key
    else if (key_arg.len == 1)
        key_arg[0]
    else
        return false;

    var state = currentChooseTreeState(ctx, pane) orelse return false;
    switch (state.tree.handleKey(key)) {
        .none => {
            try renderChooseTree(ctx, pane);
            return true;
        },
        .cancel => {
            clearChooseTreeState(ctx, pane);
            return true;
        },
        .select, .toggle_expand => {
            const selected = state.tree.selected;
            try handleChooseTreeSelect(ctx, pane, selected);
            return true;
        },
    }
}

fn formatBindingKey(buf: []u8, key: u21, mods: binding_mod.Modifiers) []const u8 {
    var pos: usize = 0;
    if (mods.ctrl) {
        @memcpy(buf[pos .. pos + 2], "C-");
        pos += 2;
    }
    if (mods.meta) {
        @memcpy(buf[pos .. pos + 2], "M-");
        pos += 2;
    }
    if (mods.shift) {
        @memcpy(buf[pos .. pos + 2], "S-");
        pos += 2;
    }

    const special: ?[]const u8 = switch (key) {
        '\r' => "Enter",
        0x1b => "Escape",
        ' ' => "Space",
        '\t' => "Tab",
        0x7f => "BSpace",
        0x100 => "Up",
        0x101 => "Down",
        0x102 => "Left",
        0x103 => "Right",
        else => null,
    };

    if (special) |name| {
        @memcpy(buf[pos .. pos + name.len], name);
        pos += name.len;
        return buf[0..pos];
    }

    if (key < 0x80) {
        buf[pos] = @truncate(key);
        pos += 1;
        return buf[0..pos];
    }

    const rendered = std.fmt.bufPrint(buf[pos..], "U+{X}", .{key}) catch "?";
    return buf[0 .. pos + rendered.len];
}

/// Map F-key names to escape sequences.
fn namedFKey(name: []const u8) ?[]const u8 {
    if (name.len < 2 or name[0] != 'F') return null;
    const num = std.fmt.parseInt(u8, name[1..], 10) catch return null;
    return switch (num) {
        1 => "\x1bOP",
        2 => "\x1bOQ",
        3 => "\x1bOR",
        4 => "\x1bOS",
        5 => "\x1b[15~",
        6 => "\x1b[17~",
        7 => "\x1b[18~",
        8 => "\x1b[19~",
        9 => "\x1b[20~",
        10 => "\x1b[21~",
        11 => "\x1b[23~",
        12 => "\x1b[24~",
        else => null,
    };
}

fn spawnShellChild(command: []const u8) CmdError!std.c.pid_t {
    var cmd_buf: [4096]u8 = .{0} ** 4096;
    if (command.len >= cmd_buf.len) return CmdError.CommandFailed;
    @memcpy(cmd_buf[0..command.len], command);

    const pid = std.c.fork();
    if (pid < 0) return CmdError.CommandFailed;

    if (pid == 0) {
        const sh: [*:0]const u8 = "/bin/sh";
        const c_flag: [*:0]const u8 = "-c";
        const cmd_z: [*:0]const u8 = @ptrCast(cmd_buf[0..command.len :0]);
        const argv = [_:null]?[*:0]const u8{ sh, c_flag, cmd_z };
        _ = execvp(sh, &argv);
        std.c.exit(127);
    }

    return pid;
}

fn waitForChildExit(pid: std.c.pid_t) CmdError!i32 {
    var status: i32 = 0;
    if (std.c.waitpid(pid, &status, 0) < 0) return CmdError.CommandFailed;
    return status;
}

fn childExitCode(status: i32) i32 {
    return @divTrunc(status, 256);
}

