        } else {
            _ = unsetenv("HOME");
        }
    }

    try std.testing.expectEqual(@as(c_int, 0), setenv("HOME", home_z, 1));

    var server = try Server.init(std.testing.allocator, "/tmp/zmux-default-config.sock");
