fn cmdSetOption(ctx: *Context, args: []const []const u8) CmdError!void {
    var is_global = false;
    var is_unset = false;
    var is_quiet = false;

    var index: usize = 0;
    while (index < args.len and args[index].len > 0 and args[index][0] == '-') : (index += 1) {
        if (std.mem.eql(u8, args[index], "-g")) {
            is_global = true;
        } else if (std.mem.eql(u8, args[index], "-u") or std.mem.eql(u8, args[index], "-U")) {
            is_unset = true;
        } else if (std.mem.eql(u8, args[index], "-q")) {
            is_quiet = true;
        } else if (std.mem.eql(u8, args[index], "-t") and index + 1 < args.len) {
            index += 1;
        }
        // -a/-F/-o/-p/-s/-w: parsed but not fully distinguished
    }

    if (index >= args.len) {
        if (!is_quiet) return CmdError.InvalidArgs;
        return;
    }

    if (is_unset) {
        // Restore option to default value.
        const opt_name = if (index < args.len) args[index] else return;
        if (isWindowOptionName(opt_name)) {
            if (is_global) {
                restoreGlobalWindowOption(ctx.server, opt_name);
                return;
            }

            const target_ctx = resolvedTargetContext(ctx, args);
            const window = target_ctx.window orelse {
                if (!is_quiet) return CmdError.WindowNotFound;
                return;
            };
            restoreDefaultWindowOption(window, opt_name);
            return;
        }
        if (is_global) {
            for (ctx.server.sessions.items) |s| {
                restoreDefaultOption(s, opt_name);
            }
        } else if (ctx.session) |s| {
            restoreDefaultOption(s, opt_name);
        }
        return;
    }

    const name = args[index];
    const value: ?[]const u8 = if (index + 1 < args.len) args[index + 1] else null;
    const val = value orelse {
        if (!is_quiet) return CmdError.InvalidArgs;
        return;
    };

    if (isWindowOptionName(name)) {
        if (is_global) {
            applyGlobalWindowOption(ctx.server, name, val) catch {
                if (!is_quiet) return CmdError.CommandFailed;
            };
            return;
        }

        const target_ctx = resolvedTargetContext(ctx, args);
        const window = target_ctx.window orelse {
            if (!is_quiet) return CmdError.WindowNotFound;
            return;
        };
        applyWindowOption(window, name, val) catch {
            if (!is_quiet) return CmdError.CommandFailed;
        };
        return;
    }

    // Global options are applied to all existing sessions and stored as
    // server defaults for future sessions.
    if (is_global) {
        applyGlobalOption(ctx.server, name, val) catch {
            if (!is_quiet) return CmdError.CommandFailed;
        };
        return;
    }

    const session = ctx.session orelse {
        if (!is_quiet) return CmdError.SessionNotFound;
        return;
    };
    applySessionOption(session, name, val) catch {
        if (!is_quiet) return CmdError.CommandFailed;
    };
}

fn restoreDefaultOption(session: *Session, name: []const u8) void {
