   259	    /// Load a configuration file by executing it as commands.
   260	    /// Returns true once a file was successfully opened, even if it was empty.
   261	    pub fn loadConfigFile(self: *Server, path: []const u8) bool {
   262	        const expanded_path = config_path.expandHomePath(self.allocator, path) catch return false;
   263	        defer self.allocator.free(expanded_path);
   264	
   265	        var path_buf: [4096]u8 = .{0} ** 4096;
   266	        if (expanded_path.len >= path_buf.len) return false;
   267	        @memcpy(path_buf[0..expanded_path.len], expanded_path);
   268	        const cpath: [*:0]const u8 = @ptrCast(path_buf[0..expanded_path.len :0]);
   269	        const fd = std.c.open(cpath, .{ .ACCMODE = .RDONLY }, @as(std.c.mode_t, 0));
   270	        if (fd < 0) return false;
   271	        defer _ = std.c.close(fd);
   272	
   273	        var content_buf: [65536]u8 = undefined;
   274	        var total: usize = 0;
   275	        while (total < content_buf.len) {
   276	            const n = std.c.read(fd, content_buf[total..].ptr, content_buf.len - total);
   277	            if (n <= 0) break;
   278	            total += @intCast(n);
   279	        }
   280	        if (total == 0) return true;
   281	
   282	        var registry = cmd.Registry.init(self.allocator);
   283	        defer registry.deinit();
   284	        registry.registerBuiltins() catch return true;
   285	
   286	        var ctx = cmd.Context{
   287	            .server = self,
   288	            .session = self.default_session,
   289	            .window = if (self.default_session) |s| s.active_window else null,
   290	            .pane = if (self.default_session) |s| if (s.active_window) |w| w.active_pane else null else null,
   291	            .allocator = self.allocator,
   292	            .registry = &registry,
   293	            .binding_manager = &self.binding_manager,
   294	        };
   295	
   296	        var parser = config_parser.ConfigParser.init(self.allocator, content_buf[0..total]);
   297	        var commands = parser.parseAll() catch return true;
   298	        defer {
   299	            for (commands.items) |*command| command.deinit(self.allocator);
   300	            commands.deinit(self.allocator);
   301	        }
   302	
   303	        for (commands.items) |*command| {
   304	            registry.executeParsed(&ctx, command) catch {};
   305	        }
   306	        return true;
   307	    }
