  3510	        return;
  3511	    }
  3512	    if (std.mem.eql(u8, name, "default-shell")) {
  3513	        try session.setDefaultShell(value);
  3514	        return;
  3515	    }
  3516	    if (std.mem.eql(u8, name, "visual-activity")) {
  3517	        session.options.visual_activity = parseBooleanValue(value) orelse return error.InvalidArgs;
  3518	        return;
  3519	    }
  3520	    if (std.mem.eql(u8, name, "status-left")) {
  3521	        const alloc = session.allocator;
  3522	        const owned = try alloc.dupe(u8, value);
  3523	        alloc.free(session.options.status_left);
  3524	        session.options.status_left = owned;
  3525	        return;
  3526	    }
  3527	    if (std.mem.eql(u8, name, "status-right")) {
  3528	        const alloc = session.allocator;
  3529	        const owned = try alloc.dupe(u8, value);
  3530	        alloc.free(session.options.status_right);
  3531	        session.options.status_right = owned;
