  3537	fn applyGlobalOption(server: *Server, name: []const u8, value: []const u8) !void {
  3538	    if (isWindowOptionName(name)) {
  3539	        return applyGlobalWindowOption(server, name, value);
  3540	    }
  3541	    // Apply to all existing sessions.
  3542	    for (server.sessions.items) |session| {
  3543	        applySessionOption(session, name, value) catch {};
  3544	    }
  3545	    // Store for future sessions by updating the server's global default shell.
  3546	    if (std.mem.eql(u8, name, "default-shell")) {
  3547	        const owned = try server.allocator.dupeZ(u8, value);
  3548	        if (server.global_default_shell) |old| server.allocator.free(old);
  3549	        server.global_default_shell = owned;
  3550	    }
  3551	}
