  3553	fn cmdSourceFile(ctx: *Context, args: []const []const u8) CmdError!void {
  3554	    if (args.len == 0) return CmdError.InvalidArgs;
  3555	
  3556	    var syntax_only = false;
  3557	    var quiet = false;
  3558	
  3559	    var i: usize = 0;
  3560	    while (i < args.len and args[i].len > 0 and args[i][0] == '-') : (i += 1) {
  3561	        if (std.mem.eql(u8, args[i], "-n")) {
  3562	            syntax_only = true;
  3563	        } else if (std.mem.eql(u8, args[i], "-q")) {
  3564	            quiet = true;
  3565	        } else if (std.mem.eql(u8, args[i], "-v")) {
  3566	            // verbose: no-op
  3567	        } else if ((std.mem.eql(u8, args[i], "-F") or std.mem.eql(u8, args[i], "-t")) and i + 1 < args.len) {
  3568	            i += 1;
  3569	        }
  3570	    }
  3571	    if (i >= args.len) return CmdError.InvalidArgs;
  3572	    const path = args[i];
  3573	
  3574	    const expanded_path = config_path.expandHomePath(ctx.allocator, path) catch return CmdError.OutOfMemory;
  3575	    defer ctx.allocator.free(expanded_path);
  3576	
  3577	    var path_buf: [4096]u8 = .{0} ** 4096;
  3578	    if (expanded_path.len >= path_buf.len) return CmdError.CommandFailed;
  3579	    @memcpy(path_buf[0..expanded_path.len], expanded_path);
  3580	    const cpath: [*:0]const u8 = @ptrCast(path_buf[0..expanded_path.len :0]);
  3581	    const fd = std.c.open(cpath, .{ .ACCMODE = .RDONLY }, @as(std.c.mode_t, 0));
  3582	    if (fd < 0) {
  3583	        if (quiet) return;
  3584	        return CmdError.CommandFailed;
  3585	    }
  3586	    defer _ = std.c.close(fd);
  3587	
  3588	    var content_buf: [65536]u8 = undefined;
  3589	    var total: usize = 0;
  3590	    while (total < content_buf.len) {
  3591	        const n = std.c.read(fd, content_buf[total..].ptr, content_buf.len - total);
  3592	        if (n <= 0) break;
  3593	        total += @intCast(n);
  3594	    }
  3595	    if (total == 0) return;

